insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-3-business-ownership:match:fdad4f5d', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Shareholders”?", "options": ["A legal document setting out each partner''s role, capital contribution, and how profits and losses will be shared.", "The owner is personally responsible for ALL debts of the business. Personal possessions can be seized to repay creditors.", "The market (London Stock Exchange in the UK) where shares in public limited companies are bought and sold by the general public.", "The owners of a limited company. Each has invested money and owns a proportion of the business."]}'::jsonb, '{"answer": 3, "explain": "“Shareholders” means: The owners of a limited company. Each has invested money and owns a proportion of the business."}'::jsonb),
('business:1-3-business-ownership:match:0f037d6f', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dividend”?", "options": ["A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital.", "A payment made to shareholders from the profits of a limited company. The financial reward for investing (and taking a risk).", "A legal document setting out each partner''s role, capital contribution, and how profits and losses will be shared.", "Money raised to start or develop a business."]}'::jsonb, '{"answer": 1, "explain": "“Dividend” means: A payment made to shareholders from the profits of a limited company. The financial reward for investing (and taking a risk)."}'::jsonb),
('business:1-3-business-ownership:match:191a2e5a', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sleeping Partner”?", "options": ["A partner who provides capital for a partnership but takes no active role in running the business.", "A large company whose shares are sold to the general public on the Stock Exchange. Has ''plc'' after its name and requires £50,000 minimum share capital.", "The owners of a limited company. Each has invested money and owns a proportion of the business.", "The legal process of forming a company, creating a separate legal identity (and limited liability) distinct from its owners."]}'::jsonb, '{"answer": 0, "explain": "“Sleeping Partner” means: A partner who provides capital for a partnership but takes no active role in running the business."}'::jsonb),
('business:1-3-business-ownership:match:b92ed3d3', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Capital”?", "options": ["A partner who provides capital for a partnership but takes no active role in running the business.", "Money raised to start or develop a business.", "A payment made to shareholders from the profits of a limited company. The financial reward for investing (and taking a risk).", "The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected."]}'::jsonb, '{"answer": 1, "explain": "“Capital” means: Money raised to start or develop a business."}'::jsonb),
('business:1-3-business-ownership:match:4ff2888a', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stock Exchange”?", "options": ["The market (London Stock Exchange in the UK) where shares in public limited companies are bought and sold by the general public.", "Money raised to start or develop a business.", "The legal process of forming a company, creating a separate legal identity (and limited liability) distinct from its owners.", "The owner''s responsibility for debts is limited to the amount originally invested. Personal possessions are protected."]}'::jsonb, '{"answer": 0, "explain": "“Stock Exchange” means: The market (London Stock Exchange in the UK) where shares in public limited companies are bought and sold by the general public."}'::jsonb),
('business:1-3-business-ownership:match:de0f6da2', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “LLP (Limited Liability Partnership)”?", "options": ["The market (London Stock Exchange in the UK) where shares in public limited companies are bought and sold by the general public.", "The owner is personally responsible for ALL debts of the business. Personal possessions can be seized to repay creditors.", "A form of partnership where owners have limited liability for business debts, but must publish financial accounts publicly.", "The legal process of forming a company, creating a separate legal identity (and limited liability) distinct from its owners."]}'::jsonb, '{"answer": 2, "explain": "“LLP (Limited Liability Partnership)” means: A form of partnership where owners have limited liability for business debts, but must publish financial accounts publicly."}'::jsonb),
('business:1-3-business-ownership:match:02d88ba3', 'business', 'business:1-3-business-ownership', '1.3 Business Ownership', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Incorporation”?", "options": ["The owner is personally responsible for ALL debts of the business. Personal possessions can be seized to repay creditors.", "A company whose shares can only be sold to family and friends with shareholder agreement. Has ''Ltd'' after its name and limited liability.", "The legal process of forming a company, creating a separate legal identity (and limited liability) distinct from its owners.", "A partner who provides capital for a partnership but takes no active role in running the business."]}'::jsonb, '{"answer": 2, "explain": "“Incorporation” means: The legal process of forming a company, creating a separate legal identity (and limited liability) distinct from its owners."}'::jsonb),
('business:1-4-business-aims-objectives:exam:857b1dd0', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q1", "question": "A business has recently changed its main objective from ''survival'' to ''growth''. What would most likely explain this change of objective?", "options": ["The business has become too big", "The business has reduced its productivity", "The business is experiencing high demand", "The business needs to lower its costs"], "hint": "Think about what would make a business feel confident enough to stop focusing on survival and start focusing on getting bigger.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The business is experiencing high demand</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A — The business has become too big:</strong> Becoming too big is not a reason to pursue growth — it would be a reason to consolidate or reduce operations, not expand further.</li><li><strong>B — The business has reduced its productivity:</strong> Reduced productivity would likely harm the business''s performance, making survival more relevant — not growth.</li><li><strong>D — The business needs to lower its costs:</strong> Lowering costs is a financial management decision, not a reason to change from survival to growth as an objective.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:exam:d2568ba4', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q2", "question": "What would help the company achieve its objective?", "options": ["Increasing the cost of its canned drinks", "Increasing the number of retail outlets it supplies", "Increasing the price of its canned drinks", "Increasing the time it takes to process orders"], "caseStudy": "DM plc manufactures canned drinks. The company''s main objective for the coming financial year is to increase its market share by 2%.", "hint": "Market share is about reaching more customers and selling more than competitors. Which option makes it easier for more customers to buy DM''s drinks?", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Increasing the number of retail outlets it supplies</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A — Increasing the cost:</strong> Higher costs reduce profit margins but do not directly increase sales. If costs rise but prices stay the same, profit falls.</li><li><strong>C — Increasing the price:</strong> Higher prices would likely reduce demand, meaning fewer cans are sold. This would decrease, not increase, market share.</li><li><strong>D — Increasing processing time:</strong> Slower order processing would delay stock reaching retailers and frustrate customers, likely reducing sales and market share.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:exam:2c7ce9dc', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q3", "question": "What would explain this difference in objectives?", "options": ["Firm A has a low market share and Firm B has a high market share", "Firm B is a start-up business and Firm A is an established business", "The owners of Firm A have less determination than the owners of Firm B", "The owners of Firm B are more confident than the owners of Firm A"], "caseStudy": "Firms A and B both operate in the same industry.\n• Firm A''s objective is to make a profit\n• Firm B''s objective is survival.", "hint": "Think about which type of business typically focuses on survival and why.", "starter": "The answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>B — Firm B is a start-up business and Firm A is an established business</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> A business with a low market share might want growth, not profit — and a high market share business would likely be aiming for profit too. This does not explain the survival objective.</li><li><strong>C:</strong> Having less determination does not lead to a profit objective — it is not a logical or relevant business reason for choosing profit over survival.</li><li><strong>D:</strong> Confidence is not a factor in choosing survival as an objective. Start-up businesses focus on survival due to competition and lack of customer base — not because owners lack confidence.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:exam:ea393462', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q4", "question": "What would explain this change of objective?", "options": ["The hair salon has already achieved its profit objective", "The hair salon has gained a lot of new customers", "The hair salon is experiencing intense competition", "The hair salon is now an established business"], "caseStudy": "Alex, a sole trader, opened a hair salon three years ago. He has recently changed the main objective of the business from ''profit'' to ''survival''.", "hint": "The objective has gone from profit DOWN to survival — something has made things harder. What would reduce sales and threaten the business?", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — The hair salon is experiencing intense competition</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> Achieving the profit objective would likely lead to a higher objective such as growth — not a switch back down to survival.</li><li><strong>B:</strong> Gaining new customers would improve revenue and profit, making survival less of a concern — not more.</li><li><strong>D:</strong> Being established suggests stability — an established business would typically aim for profit or growth, not survival.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:exam:29550f15', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Which of the following is NOT a possible reason why the two businesses have different objectives?", "options": ["One business makes coats and the other makes jeans", "Only one of the businesses makes designer clothing", "There is little innovation in the clothing industry", "They have different owners"], "caseStudy": "Two clothing manufacturers have different objectives.", "hint": "Look for the option that has NO logical link to why a business would choose a different objective.", "starter": "The answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>C — There is little innovation in the clothing industry</strong></p></div><div class=\"marks-section\"><h5>Why the other options ARE possible reasons</h5><ul><li><strong>A:</strong> Different products (coats vs jeans) may target different markets with different levels of competition or profit potential, influencing objectives.</li><li><strong>B:</strong> Making designer clothing suggests a high-price, service-focused strategy — the business is likely pursuing profit or reputation rather than growth by volume.</li><li><strong>D:</strong> Different owners have different personal ambitions, attitudes to risk, and values — this directly affects which objectives they set for the business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:exam:f549d9d5', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A business whose main objective is to survive is likely to be:", "options": ["Experiencing growth in its market share", "Making a large profit", "Well established and successful", "Working hard to stay in existence"], "hint": "Think about what ''survival'' actually means — what is the business trying to do?", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — Working hard to stay in existence</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> Growing market share is a sign of expansion and success — the opposite of a survival-focused business.</li><li><strong>B:</strong> Making a large profit means the business is performing well and would likely pursue growth or profit maximisation — not survival.</li><li><strong>C:</strong> A well-established and successful business would not have survival as its objective — it would focus on maintaining or growing profit.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:exam:ed2ff936', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'exam', 'mcq', 1, '{"num": "Q10", "question": "The ''objectives of a business'' are:", "options": ["Negative comments from the local community", "The buildings and equipment the business owns", "The items the business makes and sells", "What the business intends to achieve"], "hint": "Think about the definition of the word ''objective'' — it''s about targets and goals, not physical things.", "starter": "The answer is D because..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\"><h5>Answer</h5><p><strong>D — What the business intends to achieve</strong></p></div><div class=\"marks-section\"><h5>Why the other options are wrong</h5><ul><li><strong>A:</strong> Negative comments are stakeholder feedback — this has nothing to do with the goals the business sets for itself.</li><li><strong>B:</strong> Buildings and equipment are physical assets — these are resources the business uses, not goals it aims for.</li><li><strong>C:</strong> Products are what the business sells — a business might sell trainers, but its objective might be to make a profit or grow its market share.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-4-business-aims-objectives:mcq:6d5a74ef', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "What does ''satisficing'' mean in a business context?", "options": ["Making as much profit as possible", "Making just enough profit to provide the owner with a decent living", "Providing the best possible customer service", "Focusing on growth above all else"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: Satisficing means making just enough profit to give the business owner a decent standard of living. It is most common in smaller businesses such as sole traders who are not driven by maximum profit."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:08471be0', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "A business has recently changed its main objective from ''survival'' to ''growth''. What would most likely explain this change?", "options": ["The business has become too big", "The business has reduced its productivity", "The business is experiencing high demand", "The business needs to lower its costs"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: High demand means the business is performing well and has established itself. This gives it the confidence and resources to shift from simply staying alive (survival) to expanding (growth)."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:6f74c609', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "DM plc manufactures canned drinks. Its main objective is to increase market share by 2%. What would help achieve this?", "options": ["Increasing the cost of its canned drinks", "Increasing the number of retail outlets it supplies", "Increasing the price of its canned drinks", "Increasing the time it takes to process orders"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: By supplying more retail outlets, DM plc reaches more customers, which increases total sales. A higher share of total market sales means greater market share. Raising prices (A and C) would likely reduce sales, and slower processing (D) would harm competitiveness."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:cdc77313', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "Firms A and B both operate in the same industry. Firm A''s objective is profit; Firm B''s objective is survival. What would explain this difference?", "options": ["Firm A has a low market share and Firm B has a high market share", "Firm B is a start-up business and Firm A is an established business", "The owners of Firm A have less determination than the owners of Firm B", "The owners of Firm B are more confident than the owners of Firm A"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: New or start-up businesses typically focus on survival because they are not yet established in the market and face competition from existing firms. Established businesses, having already secured customers and revenue, can focus on higher-level objectives like profit."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:43def2b9', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "Alex, a sole trader, changed his hair salon''s objective from ''profit'' to ''survival''. What would explain this?", "options": ["The hair salon has already achieved its profit objective", "The hair salon has gained a lot of new customers", "The hair salon is experiencing intense competition", "The hair salon is now an established business"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Intense competition would reduce Alex''s sales and potentially make profit unachievable in the short term. When revenue falls due to competition, survival becomes the priority — keeping the business trading until conditions improve."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:f549d9d5', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "A business whose main objective is to survive is likely to be:", "options": ["Experiencing growth in its market share", "Making a large profit", "Well established and successful", "Working hard to stay in existence"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Survival means the business is focused on simply continuing to operate. This typically occurs during early stages or periods of difficulty — the opposite of growing market share or making large profits."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:ed2ff936', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "The ''objectives of a business'' are:", "options": ["Negative comments from the local community", "The buildings and equipment the business owns", "The items the business makes and sells", "What the business intends to achieve"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: Business objectives are what the business aims to achieve — targets or goals such as profit, growth, survival, market share, or providing a service. They are not physical assets (B), products (C), or negative feedback (A)."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:7d244222', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT normally an aim of a business which is just starting?", "options": ["Survival", "To become established in the market", "To become a plc", "To try to make a profit"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Becoming a PLC is a long-term structural change requiring significant growth, established reputation, and shareholder investment. A brand new business focuses on survival, building its name, and making early profits — not complex ownership structures."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:00e7a3fd', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "Two clothing manufacturers have different objectives. Which of the following is NOT a possible reason for this?", "options": ["One business makes coats and the other makes jeans", "Only one of the businesses makes designer clothing", "There is little innovation in the clothing industry", "They have different owners"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: The level of innovation in an industry does not directly cause different businesses within it to have different objectives. Different products (A), market positioning (B), and owner attitudes (D) are all genuine reasons why two businesses may pursue different goals."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:0eec2019', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "A business might want to grow because:", "options": ["It sees the opportunity of making more profit", "Growth will mean more people working in the business", "It is the best objective to have", "It will guarantee more profit"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: Businesses pursue growth because a larger business can generate higher revenues and therefore higher profits. Growth does not guarantee profit (D is wrong), and simply having more employees (B) or it being ''best'' (C) are not valid motivations."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:02357c5e', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "A business might change its aims and objectives because:", "options": ["All businesses change their objectives after a year", "A new competitor has become very successful", "It feels that a change will always bring more profits", "It is essential to change objectives as a business grows"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: External factors like new successful competitors can force a business to rethink its objectives — for example switching from growth to survival if competition is fierce. The other options contain false absolutes: not all businesses change after a year (A), and change does not always increase profits (C)."}'::jsonb),
('business:1-4-business-aims-objectives:mcq:ca1658c5', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'mcq', 'mcq', 1, '{"question": "Which of the following best describes ''market share''?", "options": ["The total value of all sales in a market", "The number of competitors a business faces", "A business''s sales as a percentage of total market sales", "The profit a business earns from each sale"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: Market share is expressed as a percentage showing how much of the total market a business accounts for. It is calculated as (Business sales ÷ Total market sales) × 100."}'::jsonb),
('business:1-4-business-aims-objectives:tf:ecdeac98', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "All businesses have profit as their main objective."}'::jsonb, '{"answer": false, "explain": "FALSE. Not all businesses prioritise profit. New businesses often focus on survival, small businesses may satisfice, and some businesses (especially in the public sector or community-focused businesses) prioritise providing a service above profit."}'::jsonb),
('business:1-4-business-aims-objectives:tf:a20cc97c', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Satisficing means making as much profit as possible."}'::jsonb, '{"answer": false, "explain": "FALSE. Satisficing means making just enough profit to give the owner a decent standard of living. It is the opposite of profit maximisation and is common among sole traders who value a good work-life balance over maximum earnings."}'::jsonb),
('business:1-4-business-aims-objectives:tf:b0fb0539', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Market share is expressed as a percentage of total sales in a market."}'::jsonb, '{"answer": true, "explain": "TRUE. Market share = (Business sales ÷ Total market sales) × 100. For example, if a business sells 100 tables out of 1,000 sold in the market, its market share is 10%."}'::jsonb),
('business:1-4-business-aims-objectives:tf:ae8edb3a', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "A new business is most likely to have survival as its main objective."}'::jsonb, '{"answer": true, "explain": "TRUE. New businesses face established competition, must build a reputation from scratch, and often have limited resources. Simply keeping the business trading through the first few months is a major achievement."}'::jsonb),
('business:1-4-business-aims-objectives:tf:fce1a9ac', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "A PLC must focus on profit because shareholders expect dividends."}'::jsonb, '{"answer": true, "explain": "TRUE. Shareholders invest in a PLC expecting a financial return (dividends). These are paid from profits, so a PLC must generate sufficient profit to keep shareholders satisfied — otherwise they may sell their shares, reducing the company''s value."}'::jsonb),
('business:1-4-business-aims-objectives:tf:081b233c', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Business objectives never change once they have been set."}'::jsonb, '{"answer": false, "explain": "FALSE. Business objectives change regularly as circumstances evolve. A new business may start with survival, move to profit, then growth. A business in difficulty might revert to survival. Changes in competition, the economy, or owner ambitions all cause objectives to shift."}'::jsonb),
('business:1-4-business-aims-objectives:tf:cac757a0', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "A sole trader can decide their own objectives without answering to shareholders."}'::jsonb, '{"answer": true, "explain": "TRUE. A sole trader owns the entire business themselves. They are free to set their own objectives — whether that is satisficing, providing a community service, or growing — without needing approval from shareholders or a board of directors."}'::jsonb),
('business:1-4-business-aims-objectives:tf:7e774484', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Growth is always the most important business objective."}'::jsonb, '{"answer": false, "explain": "FALSE. Growth is one of several objectives, and it is not always the most important. Many small businesses are content to remain the same size. Survival takes priority during difficult periods, and some businesses value service or satisficing over expansion."}'::jsonb),
('business:1-4-business-aims-objectives:tf:23f8aca3', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Providing excellent customer service can help a business achieve other objectives such as profit and survival."}'::jsonb, '{"answer": true, "explain": "TRUE. Good service builds loyalty, attracts new customers, and generates positive word-of-mouth. This increases sales, which in turn raises revenue and profit — helping achieve a range of business objectives simultaneously."}'::jsonb),
('business:1-4-business-aims-objectives:tf:1a00e0ad', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "A business facing intense competition might switch its objective from growth to survival."}'::jsonb, '{"answer": true, "explain": "TRUE. If competition is severe enough to reduce sales and threaten the business''s existence, maintaining growth becomes unrealistic. The priority becomes keeping the business alive until conditions improve."}'::jsonb),
('business:1-4-business-aims-objectives:tf:01897513', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Taking over a competitor is one way a business can increase its market share."}'::jsonb, '{"answer": true, "explain": "TRUE. By acquiring a competitor, a business absorbs that competitor''s customers and sales. This directly increases its share of the total market."}'::jsonb),
('business:1-4-business-aims-objectives:tf:1003c3f0', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tf', 'tf', 1, '{"question": "Expansion plans are typically accelerated when a business is in financial difficulty."}'::jsonb, '{"answer": false, "explain": "FALSE. When a business is in financial difficulty, expansion plans are postponed or cancelled entirely. The focus shifts to reducing losses and ensuring survival — not investing in costly growth strategies."}'::jsonb),
('business:1-4-business-aims-objectives:learn:de091196', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>Every business needs a direction — a set of goals that guide all its decisions. These are known as <strong>business aims and objectives</strong>.</p>\n<ul>\n  <li><strong>Business Objectives:</strong> What the business aims to achieve. These can include survival, profit, growth, market share, and providing a service.</li>\n  <li><strong>Profit:</strong> The difference between revenue (money coming in) and costs (money going out). Revenue − Costs = Profit.</li>\n  <li><strong>Satisficing:</strong> Making just enough profit to give the business owner a decent standard of living. More common in smaller businesses such as sole traders.</li>\n  <li><strong>Growth:</strong> Where a business becomes larger — for example by making more products, opening more stores, or selling in new markets.</li>\n  <li><strong>Market Share:</strong> The percentage of the total market that a business holds. Shown as a percentage of total sales in the industry.</li>\n  <li><strong>Survival:</strong> When a business manages to keep trading, often during its early months or in times of difficulty.</li>\n  <li><strong>Providing a Service:</strong> Ensuring the needs of the customer are met, often prioritised over maximising profit.</li>\n  <li><strong>Evolving:</strong> The way a business develops and changes over time — becoming bigger or smaller, selling different goods, or operating in different ways.</li>\n</ul>", "question": "What is ''satisficing''?", "options": ["Gaining the largest possible share of the market", "Making just enough profit for a decent standard of living", "Making the maximum possible profit for shareholders", "Keeping the business trading during a difficult period"]}'::jsonb, '{"answer": 1, "explain": "The card defines satisficing as making just enough profit for a decent standard of living, which is more common in smaller businesses such as sole traders."}'::jsonb),
('business:1-4-business-aims-objectives:learn:26848c6c', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'learn', 'mcq', 1, '{"readingTitle": "The Five Main Business Objectives", "reading": "<p>All businesses have at least one objective, but the most common objectives are:</p>\n<ul>\n  <li><strong>Profit:</strong> Most businesses aim to make a profit. Some aim to <em>maximise</em> profit (make as much as possible), while others aim to <em>satisfice</em> (make just enough). Too much focus on profit can damage reputation if customers feel they are being exploited.</li>\n  <li><strong>Growth:</strong> Becoming larger — through more sales, more outlets, or a higher market share. Important for PLCs that need to pay increasing dividends to shareholders. Not all businesses want to grow; many smaller businesses are happy to stay the same size.</li>\n  <li><strong>Market Share:</strong> Gaining a greater percentage of total sales in an industry. For example, if 1,000 tables are sold nationally and a business sells 100, its market share is 10%. A business might take over a competitor to increase its share.</li>\n  <li><strong>Survival:</strong> Simply keeping the business going. Especially important for new businesses in their first months, or for any business facing falling sales, new competition, or economic difficulty. Normally a temporary but vital objective.</li>\n  <li><strong>Providing a Service:</strong> Putting customer satisfaction first, even if it means less profit. Common in smaller local businesses or those that build their reputation on excellent service. Can lead to awards, loyal customers, and long-term success.</li>\n</ul>\n<div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business ÷ Total sales in the market) &times; 100\n</div>", "question": "A business sells 100 out of 1,000 tables sold nationally. What is its market share?", "options": ["1%", "90%", "10%", "100%"]}'::jsonb, '{"answer": 2, "explain": "Using the card''s example and the formula (business sales ÷ total market sales) × 100, 100 ÷ 1,000 × 100 = 10%."}'::jsonb),
('business:1-4-business-aims-objectives:learn:ddd5050e', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages of Each Objective", "reading": "<p>Each objective has strengths and weaknesses depending on the situation of the business.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Profit Maximisation</div>\n    <div class=\"pro-item\"><strong>Rewards owners:</strong> Maximising profit ensures shareholders and owners receive the highest possible return for the risks they have taken.</div>\n    <div class=\"pro-item\"><strong>Funds future growth:</strong> High profits can be reinvested to expand the business, open new premises, or research new products.</div>\n    <div class=\"con-item\"><strong>Damages reputation:</strong> Customers and the public may react negatively if a business is seen as purely profit-driven, reducing sales in the long run.</div>\n    <div class=\"con-item\"><strong>Short-term focus:</strong> Chasing maximum profit can lead to cutting corners on quality or customer service.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✓ Survival</div>\n    <div class=\"pro-item\"><strong>Keeps business alive:</strong> For new or struggling businesses, simply continuing to trade is a crucial achievement that allows future recovery.</div>\n    <div class=\"pro-item\"><strong>Realistic target:</strong> A clear, achievable focus that helps owners prioritise essential costs and decisions during tough times.</div>\n    <div class=\"con-item\"><strong>Not sustainable long-term:</strong> A business cannot survive indefinitely without making profit — survival must eventually lead to other objectives.</div>\n    <div class=\"con-item\"><strong>Limits investment:</strong> When focused on survival, a business cannot invest in growth, marketing, or new technology.</div>\n  </div>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Growth</div>\n    <div class=\"pro-item\"><strong>Increases profit potential:</strong> A larger business can sell more, benefit from economies of scale, and generate higher revenues.</div>\n    <div class=\"pro-item\"><strong>Greater market power:</strong> Growth can reduce competition by taking over rivals or securing exclusive supplier deals.</div>\n    <div class=\"con-item\"><strong>Loss of control:</strong> Rapid growth can make it harder to maintain quality, communication, and customer service standards.</div>\n    <div class=\"con-item\"><strong>Not always desired:</strong> Many smaller business owners are content to stay small and avoid the stress and risk of expansion.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✓ Providing a Service</div>\n    <div class=\"pro-item\"><strong>Builds loyalty:</strong> Customers who receive excellent service are more likely to return and recommend the business to others.</div>\n    <div class=\"pro-item\"><strong>Strong reputation:</strong> Businesses known for great service can earn awards and stand out in competitive markets.</div>\n    <div class=\"con-item\"><strong>Lower profit margins:</strong> Investing heavily in service quality can increase costs, reducing overall profitability.</div>\n    <div class=\"con-item\"><strong>Hard to measure:</strong> Unlike profit or market share, the success of a service objective is difficult to quantify precisely.</div>\n  </div>\n</div>", "question": "According to this card, what is a key disadvantage of profit maximisation as an objective?", "options": ["It prevents the business from ever reinvesting in growth", "It can damage reputation if seen as purely profit-driven", "It makes market share impossible to calculate", "It guarantees the business will lose customers immediately"]}'::jsonb, '{"answer": 1, "explain": "The card states that customers and the public may react negatively if a business is seen as purely profit-driven, reducing sales in the long run."}'::jsonb),
('business:1-4-business-aims-objectives:learn:04e07798', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'learn', 'mcq', 1, '{"readingTitle": "How & Why Objectives Change as Businesses Evolve", "reading": "<p>A business''s objectives are never fixed forever. As circumstances change, so do the goals a business sets itself. There are three key stages to consider:</p>\n\n<p><strong>1. When a Business Starts</strong></p>\n<ul>\n  <li>The main objective is almost always <strong>survival</strong> — simply getting through the first few months.</li>\n  <li>New businesses face established competitors who may lower prices to squeeze them out of the market.</li>\n  <li>They must build a reputation and find loyal customers from scratch.</li>\n  <li>Some new businesses with experienced owners and contacts may aim for profit from day one.</li>\n</ul>\n\n<p><strong>2. As a Business Grows</strong></p>\n<ul>\n  <li>Once established, owners with ambition may shift from satisficing to <strong>profit maximisation</strong>.</li>\n  <li>Profit can then be reinvested to fund <strong>growth</strong> — new premises, new products, or taking over a competitor.</li>\n  <li>A sole trader may convert to a limited company, attracted by limited liability as personal wealth grows.</li>\n  <li>At some point a business may choose to <em>stop</em> growing — for example, when controlling more stores would reduce quality or customer service.</li>\n  <li>Rapid growth can cause a business to lose sight of customers, so the objective may shift back to <strong>providing a service</strong>.</li>\n</ul>\n\n<p><strong>3. When a Business is in Difficulty</strong></p>\n<ul>\n  <li>Falling profits or losses make profit maximisation an unrealistic objective — <strong>survival</strong> takes priority.</li>\n  <li>Expansion plans are postponed or cancelled entirely.</li>\n  <li>In extreme cases, businesses must close down parts of their operations to reduce losses.</li>\n</ul>", "question": "When a business is in financial difficulty, what typically happens to its objectives according to this card?", "options": ["Market share automatically increases as competitors struggle too", "Expansion plans are cancelled as the focus shifts to survival", "Profit maximisation becomes easier to achieve than before", "The business immediately converts to a PLC to raise more capital"]}'::jsonb, '{"answer": 1, "explain": "The card states that falling profits make profit maximisation unrealistic, survival takes priority, and expansion plans are postponed or cancelled."}'::jsonb),
('business:1-4-business-aims-objectives:learn:118dbaee', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'learn', 'mcq', 1, '{"readingTitle": "Why Different Businesses Have Different Objectives", "reading": "<p>Not all businesses will have the same objectives. The objective a business sets depends on several key factors:</p>\n<ul>\n  <li><strong>Size of the business:</strong> A sole trader can set whatever objective they like without answering to anyone. A PLC must satisfy shareholders who expect rising dividends — meaning profit and growth are essential.</li>\n  <li><strong>Attitude of the owner(s):</strong> Some owners are driven by ambition; others are happy to earn a comfortable living without expanding. Personal motivation shapes objectives significantly.</li>\n  <li><strong>Stage of development:</strong> New businesses tend to focus on survival or establishing themselves. Mature businesses focus on profit or growth.</li>\n  <li><strong>Level of competition:</strong> A business facing heavy competition (e.g., supermarkets) may focus on survival or providing a better service rather than growth. Aldi and Lidl grew by offering something different (lower prices) in a competitive market.</li>\n  <li><strong>Economic conditions:</strong> During a recession, businesses shift focus to survival. During periods of growth, they may invest in expansion.</li>\n  <li><strong>Values of the business:</strong> Some businesses prioritise community service or social responsibility, keeping prices low even at the expense of profit.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Aldi & Tesco</h4>\n  <p>Tesco — a large established PLC — prioritises profit and market share, driven by shareholder expectations. Aldi, entering the UK market as a challenger, focused on growth by offering lower prices than rivals. Meanwhile, a small independent butcher may focus on providing excellent service to the local community, with satisficing profit as the main goal. Three businesses, three very different objectives — all shaped by their size, ownership, and market context.</p>\n</div>", "question": "In the Aldi & Tesco case study, why does Tesco prioritise profit and market share while a small independent butcher might satisfice instead?", "options": ["Butchers are legally required to prioritise service over profit", "Tesco is a large PLC answerable to shareholders; the butcher is not", "Tesco has no competitors, so it does not need to focus on market share", "Tesco sells fewer products than the butcher, so it must charge higher prices"]}'::jsonb, '{"answer": 1, "explain": "The case study shows objectives are shaped by size, ownership, and market context — Tesco''s PLC status means shareholder expectations drive profit and market share, while a small independent butcher can focus on service and satisficing."}'::jsonb),
('business:1-4-business-aims-objectives:learn:80232424', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'learn', 'mcq', 1, '{"readingTitle": "Objectives Linked to Business Ownership", "reading": "<p>The type of business ownership directly influences which objectives are most appropriate.</p>\n<ul>\n  <li><strong>Sole Trader:</strong> One owner who controls everything. Objectives are personal — often satisficing (making enough to live on) or providing a service to the local community. Growth may not be desired.</li>\n  <li><strong>Partnership:</strong> Partners may have different personal ambitions (as seen in the WYW case study — Rick wanted growth, Francis wanted profit). This can cause conflict over objectives.</li>\n  <li><strong>Private Limited Company (Ltd):</strong> Shareholders want returns, but the close ownership structure means the business can balance profit with values. May aim for growth or market share.</li>\n  <li><strong>Public Limited Company (PLC):</strong> Shareholders on the stock market demand high dividends, which requires consistent profit and growth. Objectives are largely driven by financial performance.</li>\n</ul>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Benefits of Having Clear Objectives</div>\n    <div class=\"pro-item\"><strong>Direction:</strong> All employees and stakeholders understand what the business is trying to achieve.</div>\n    <div class=\"pro-item\"><strong>Decision-making:</strong> Objectives help managers make consistent decisions that align with business goals.</div>\n    <div class=\"pro-item\"><strong>Motivation:</strong> Clear targets give employees and owners something to work towards.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Risks of Poorly Set Objectives</div>\n    <div class=\"con-item\"><strong>Conflict:</strong> Different stakeholders (e.g., partners) may want different objectives, leading to disagreement.</div>\n    <div class=\"con-item\"><strong>Inflexibility:</strong> Sticking rigidly to an objective when circumstances change can harm the business.</div>\n    <div class=\"con-item\"><strong>Unrealistic targets:</strong> Setting objectives that are too ambitious can demoralise staff and lead to poor decisions.</div>\n  </div>\n</div>", "question": "Why is a PLC''s objective-setting most constrained by shareholders, compared to a sole trader?", "options": ["PLCs are legally banned from setting a survival objective", "Sole traders must always seek shareholder approval before setting objectives", "PLCs cannot change their objectives once the business is formed", "PLC shareholders demand high dividends, requiring profit and growth"]}'::jsonb, '{"answer": 3, "explain": "The card explains that PLC shareholders demand high dividends, meaning objectives are largely driven by financial performance, unlike a sole trader whose objectives are personal."}'::jsonb),
('business:1-4-business-aims-objectives:misc:685b5498', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All businesses have profit as their main objective.</p><p><strong>✅ The correct idea:</strong> This is one of the most common misconceptions in GCSE Business. Many businesses — especially new ones — focus on survival. Public sector organisations, charities, and community businesses often prioritise service over profit. Always read the case study to identify the actual objective.</p>", "question": "Why is it wrong to assume all businesses have profit as their main objective?", "options": ["New or community businesses often prefer survival or service", "All businesses actually aim for market share, not profit", "Only sole traders are legally allowed to aim for profit", "Profit is only relevant to businesses in the public sector"]}'::jsonb, '{"answer": 0, "explain": "The card explains that new businesses often focus on survival while public sector, charity, and community businesses often prioritise service over profit — always check the case study for the actual objective."}'::jsonb),
('business:1-4-business-aims-objectives:misc:942ce9a7', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Growth always leads to more profit.</p><p><strong>✅ The correct idea:</strong> Growth can increase revenue but does not guarantee more profit. If a business lowers prices to attract more customers, profit per unit may fall. Rapid growth also increases costs. The mark scheme specifically states that growth does NOT guarantee profit.</p>", "question": "Why does growth not always guarantee more profit?", "options": ["Growth is defined as an increase in profit, so the two always rise together", "Cutting prices to attract customers and rising expansion costs reduce profit", "Growth only affects market share, never revenue or costs", "The mark scheme treats growth and profit as identical terms"]}'::jsonb, '{"answer": 1, "explain": "The card explains that lowering prices to attract customers can reduce profit per unit, and rapid growth increases costs, so the mark scheme states growth does NOT guarantee profit."}'::jsonb),
('business:1-4-business-aims-objectives:misc:88a72aed', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A business only ever has one objective at a time.</p><p><strong>✅ The correct idea:</strong> Businesses often pursue multiple objectives simultaneously. A business might aim for growth AND profit AND providing good service at the same time. The objectives are also often linked — good service leads to more customers, which leads to higher sales, which improves profit.</p>", "question": "Can a business pursue more than one objective at the same time?", "options": ["No, a business must choose exactly one objective and stick to it permanently", "Yes, businesses often pursue linked objectives together, e.g. growth and profit", "Yes, but only PLCs are allowed to have more than one objective", "No, objectives are mutually exclusive by definition in business theory"]}'::jsonb, '{"answer": 1, "explain": "The card corrects the misconception by explaining businesses often pursue multiple objectives simultaneously, and that objectives such as service, sales and profit are often linked."}'::jsonb),
('business:1-4-business-aims-objectives:misc:18ea0fd1', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Once a business sets its objectives, they stay the same forever.</p><p><strong>✅ The correct idea:</strong> Business objectives evolve constantly. Changes in competition, economic conditions, the owner''s ambitions, or the business''s financial position can all trigger a shift in objectives. Examiners expect students to recognise that objectives are dynamic, not fixed.</p>", "question": "What do examiners expect students to recognise about business objectives?", "options": ["That objectives can only change if the owner retires", "That only PLCs are able to change their objectives over time", "That objectives are dynamic, shifting with competition or ambition", "That objectives are fixed permanently once a business is registered"]}'::jsonb, '{"answer": 2, "explain": "The card states that changes in competition, economic conditions, owner ambitions, or financial position can all trigger a shift, and examiners expect students to recognise objectives are dynamic, not fixed."}'::jsonb),
('business:1-4-business-aims-objectives:misc:097c34ca', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Survival means the business is failing.</p><p><strong>✅ The correct idea:</strong> Survival is a legitimate and rational business objective — especially for new businesses or those facing temporary difficulty. Having survival as an objective shows the business is realistic about its situation. It is not a sign of failure; it is often a sensible short-term strategy.</p>", "question": "Does having survival as an objective mean a business is failing?", "options": ["No, but it can only be chosen by public limited companies", "Yes, only businesses about to close ever set survival as an objective", "Yes, survival is always a sign of business failure", "No, it is a legitimate strategy showing the business is realistic"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that survival equals failure, stating it is a legitimate, rational, and often sensible short-term strategy, especially for new or struggling businesses."}'::jsonb),
('business:1-4-business-aims-objectives:misc:b71f2344', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Market share and profit are the same thing.</p><p><strong>✅ The correct idea:</strong> Market share is the percentage of total market sales held by a business. A business can have a high market share but low profit (e.g., if it has cut prices to gain customers). They are related but different concepts with different formulas.</p>", "question": "Why are market share and profit not the same thing?", "options": ["Market share is only measured in businesses that make no profit at all", "Profit and market share always rise and fall together by definition", "Market share is a measure of costs, while profit measures revenue only", "A business can have a high market share but low profit if it cut prices"]}'::jsonb, '{"answer": 3, "explain": "The card explains they are related but different concepts with different formulas, giving the example of a business with high market share but low profit due to price cuts."}'::jsonb),
('business:1-4-business-aims-objectives:misc:3e425ea1', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All large businesses want to grow.</p><p><strong>✅ The correct idea:</strong> Not all large businesses are pursuing growth. Some may have reached a size at which further growth would reduce control or quality. A business might shift its objective to maintaining current profit levels rather than expanding further.</p>", "question": "Why might a large business choose NOT to pursue further growth?", "options": ["Large businesses never have enough profit to fund further growth", "Further growth could reduce control or quality, so profit is safer", "Growth objectives are only available to sole traders and partnerships", "Large businesses are legally prevented from growing beyond a certain size"]}'::jsonb, '{"answer": 1, "explain": "The card explains some large businesses may have reached a size where further growth reduces control or quality, so they shift focus to maintaining current profit rather than expanding."}'::jsonb),
('business:1-4-business-aims-objectives:misc:a6115c79', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Satisficing is a strategy used by lazy business owners.</p><p><strong>✅ The correct idea:</strong> Satisficing is a perfectly rational and deliberate business strategy. Many sole traders choose to earn a comfortable income without the stress and risk of expansion. It reflects the personal priorities of the owner, not a lack of ambition or effort.</p>", "question": "What does satisficing actually reflect about a business owner, according to this card?", "options": ["A lack of effort and ambition on the part of the owner", "An inability to calculate the business''s true profit figures", "The owner''s personal priorities, not laziness or ambition", "A legal requirement placed on all sole traders"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that satisficing shows laziness, explaining it is a rational, deliberate strategy reflecting the owner''s personal priorities rather than a lack of ambition."}'::jsonb),
('business:1-4-business-aims-objectives:tips:6c2759db', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1–2 marks — One Point. Full Stop. Move On.", "reading": "\n      <p>A <strong>''State'' or ''Identify''</strong> question needs one clear, specific point per mark. No explanation needed. No paragraphs. Just a direct answer.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li>One clear, specific point = 1 mark ✅</li>\n        <li>A vague or generic answer = 0 marks ❌</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"To make money.\"</em><br/>\n      Too vague — could apply to any business in any situation.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"Survival.\"</em> or <em>\"To increase market share.\"</em><br/>\n      Specific, uses the correct business terminology.</p>\n      <p><strong>⚠️ For 2-mark ''State two'' questions:</strong> Write two separate points clearly numbered. Do NOT write one long sentence — examiners award one mark per identified objective.</p>\n    ", "question": "For a ''State'' or ''Identify'' question, how should marks be earned?", "options": ["A judgement followed by a justification using case study detail", "A full paragraph explaining the reasoning behind each point", "One clear, specific point per mark, with no explanation needed", "One long combined sentence covering all required points"]}'::jsonb, '{"answer": 2, "explain": "The card''s formula states one clear, specific point equals 1 mark, while a vague or generic answer earns 0 marks — no explanation is needed for ''State'' or ''Identify'' questions."}'::jsonb),
('business:1-4-business-aims-objectives:tips:0151502f', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Point + Reason = Full Marks", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question wants a point AND a reason. You must go one step further than just naming the objective.</p>\n      <p><strong>The Formula:</strong> Make a point (K) → Briefly explain why using the business context (APP)</p>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"The Works may have a different objective to Saranne because The Works is bigger.\"</em><br/>\n      Names a difference but doesn''t explain why size leads to different objectives.</p>\n      <p><strong>✅ Good Answer (2 marks):</strong><br/>\n      <em>\"The Works is a large established retailer (APP) so it can pursue growth or profit, whereas Saranne is starting a new business and must focus on survival to get through the first few months (APP).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Both marks require context. Generic answers about \"bigger businesses want more profit\" without linking to the case study will only score 1 mark at best.</p>\n    ", "question": "What must a 2-mark ''Explain'' answer include to score full marks?", "options": ["Three separate steps: understanding, application, and analysis", "A point plus a reason, explained using the business context", "Only the correct keyword, with no further detail required", "A judgement followed by two pieces of case study evidence"]}'::jsonb, '{"answer": 1, "explain": "The card''s formula for ''Explain'' questions is: make a point (K) then briefly explain why using the business context (APP) — a generic answer without context scores only 1 mark at best."}'::jsonb),
('business:1-4-business-aims-objectives:tips:166195aa', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark <strong>''Analyse''</strong> question is worth exactly three steps. Miss any one of them and you lose a mark. This is the most tested question format in this topic.</p>\n      <p><strong>The Three Steps:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the theory or benefit clearly using business terminology.</li>\n        <li><strong>Step 2 — Application (APP):</strong> Quote or directly reference the case study. You CANNOT score analysis marks without this.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the <em>impact</em> on the business — specifically how it affects costs, revenue, reputation, profit, or operations.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1 mark):</strong><br/>\n      <em>\"If Samsung values its people, it will make better products and earn more money.\"</em><br/>\n      No application to Samsung from the case study. No specific impact stated.</p>\n      <p><strong>✅ Good Answer (3 marks):</strong><br/>\n      <em>\"When a business invests in its people, employees perform better at their jobs (U). For Samsung, which aims to produce superior products and compete with Apple (APP), well-trained workers can achieve this aim, leading to increased sales and greater revenue for the business (AN).\"</em></p>\n      <p><strong>🚫 Knowledge Dumping Alert:</strong> Do NOT write everything you know about business aims. Answer the specific question — one focused chain of reasoning scores more than three vague points.</p>\n      <p><strong>Sentence Starters:</strong><br/>\n      \"When a business sets a high value on... (U)\"<br/>\n      \"In the case of [Business Name], which... (APP)\"<br/>\n      \"This means that... / As a result, the business will... (AN)\"</p>\n    ", "question": "What are the three required steps for a 3-mark ''Analyse'' question, according to this card?", "options": ["State, Explain, Evaluate fully", "Understanding, Application, Analysis", "Knowledge, Judgement, Justification", "Definition, Example, Conclusion"]}'::jsonb, '{"answer": 1, "explain": "The card calls this ''the Holy Trinity'': Understanding (state the theory), Application (reference the case study), and Analysis (explain the impact) — missing any one loses a mark."}'::jsonb),
('business:1-4-business-aims-objectives:tips:493e5c02', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 3 marks (Judgement + Justification) — Judge It — Then Justify It With Context", "reading": "\n      <p>The 3-mark OCR evaluation question in this topic is unique — it awards <strong>1 mark for a clear judgement</strong> and <strong>2 marks for a precise, contextual justification</strong>.</p>\n      <p><strong>The Structure:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> Make a clear, decisive statement. No explanation needed yet. \"I think people are more important than technology for Samsung.\"</li>\n        <li><strong>Justification (2 marks):</strong> Use specific detail from the case study to explain WHY. This must go beyond simply repeating the case study — you need to show how the evidence supports your judgement.</li>\n      </ul>\n      <p><strong>❌ Bad Justification (0–1 marks):</strong><br/>\n      <em>\"Because Samsung wants to produce superior products and people help them do this.\"</em><br/>\n      This just repeats the case study without showing understanding of the link.</p>\n      <p><strong>✅ Good Justification (2 marks):</strong><br/>\n      <em>\"Even the best technology still requires skilled people to design, operate, and improve it. If Samsung places high value on its people, workers will be motivated to outperform rivals like Apple — the business most likely to threaten Samsung''s position as a world leader.\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> You must use the case study detail — not just repeat it. Examiners call this \"using (not simply repeating)\" the information.</p>\n      <p><strong>Sentence Starters:</strong><br/>\n      \"I believe that [option] is more important because... (Judgement)\"<br/>\n      \"The evidence from the case study shows that... (Justification)\"<br/>\n      \"Without [factor], Samsung would not be able to... (Justification)\"</p>\n    ", "question": "In this 3-mark ''Judgement + Justification'' evaluate question, how are the marks split?", "options": ["1 mark for the judgement and 2 marks for a second, opposing judgement", "3 marks are given only for restating the case study in full", "All 3 marks are awarded solely for using the word ''because''", "1 mark for a judgement, 2 marks for a contextual justification"]}'::jsonb, '{"answer": 3, "explain": "The card states this question type awards 1 mark for a clear judgement and 2 marks for a justification that uses specific case study detail, not simply repeats it."}'::jsonb),
('business:1-4-business-aims-objectives:tips:7c57f728', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Argue Both Sides, Then Deliver Your Verdict", "reading": "\n      <p>A 7-mark evaluation question wants you to build a <strong>balanced argument</strong> and reach a <strong>justified conclusion</strong>. Think of it as two 3-mark analyses followed by a decision.</p>\n      <p><strong>The Four-Paragraph Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1 — For:</strong> Knowledge + Understanding of why one objective/option is beneficial (U)</li>\n        <li><strong>Paragraph 2 — For (Applied):</strong> Apply to the case study business + analyse the impact (APP + AN)</li>\n        <li><strong>Paragraph 3 — Against:</strong> Apply the counter-argument to the case study + analyse (APP + AN)</li>\n        <li><strong>Paragraph 4 — Conclusion:</strong> Decision + Context-linked reason + Impact/consequence (EVAL ×3)</li>\n      </ul>\n      <p><strong>The Conclusion Must Include:</strong></p>\n      <ul>\n        <li><strong>Decision:</strong> \"Overall, I recommend that WYW should/should not have profit as its objective...\"</li>\n        <li><strong>Context:</strong> \"...because, as the text states, the business is a partnership and both owners need to agree...\"</li>\n        <li><strong>Impact/Reasoning:</strong> \"...and without an agreed objective, the business risks conflict between partners which could threaten its long-term success.\"</li>\n      </ul>\n      <p><strong>🚫 Common Mistake:</strong> Students write a conclusion that just repeats their earlier points. A conclusion that adds no new reasoning scores zero evaluation marks. Use the \"It depends on...\" or \"However, this is only true if...\" formula to add depth.</p>\n      <p><strong>⚠️ Do NOT write a conclusion for 3-mark or 6-mark questions</strong> — there are zero evaluation marks available for those.</p>\n    ", "question": "What must a strong conclusion in a 7-mark evaluate answer do, according to this card?", "options": ["Add new reasoning: a decision, context, and impact — not repeats", "List every objective covered in the topic, regardless of relevance", "Avoid making a decision so as not to seem biased", "Simply restate the strongest point made in paragraph one"]}'::jsonb, '{"answer": 0, "explain": "The card warns that a conclusion which just repeats earlier points scores zero evaluation marks; it must include a decision, context, and impact/reasoning to add new depth."}'::jsonb),
('business:1-4-business-aims-objectives:tips:7622fd2b', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'tips', 'mcq', 1, '{"readingTitle": "Common Trap — Application — No Case Study = No APP or AN Marks", "reading": "\n      <p>This is the single biggest reason students lose marks in Business exams. You <strong>cannot</strong> score application or analysis marks without directly referencing the case study business.</p>\n      <p><strong>The Rule:</strong> Every analysis point must be anchored to the specific business in the question.</p>\n      <p><strong>❌ No Application (loses APP + AN marks):</strong><br/>\n      <em>\"A business that values its people will produce better products and earn more profit.\"</em><br/>\n      This could describe any business. The examiner awards zero application marks.</p>\n      <p><strong>✅ With Application:</strong><br/>\n      <em>\"Samsung, which faces strong competition from Apple in the technology market (APP), will be able to produce superior products if its people are well-trained, leading to repeat customers and higher long-term revenue (AN).\"</em></p>\n      <p><strong>How to Apply:</strong> Use the business''s name, quote figures or facts from the case study (e.g. \"135 stores\", \"over 4,800 employees\", \"7% of UK electricity\"), or reference the specific market or situation described.</p>\n      <p><strong>Sentence Starters for Application:</strong><br/>\n      \"In the case of [Business Name]...\"<br/>\n      \"As the text states, [Business] operates in...\"<br/>\n      \"Because [Business] has [specific detail from case study]...\"</p>\n    ", "question": "According to this card, what happens if an analysis point does not reference the case study business?", "options": ["The examiner still awards full marks if the knowledge point is correct", "The examiner awards zero application and analysis marks", "Only the analysis mark is lost, but application is still awarded", "It only affects marks on 7-mark evaluate questions, not shorter ones"]}'::jsonb, '{"answer": 1, "explain": "The card states you cannot score application or analysis marks without directly referencing the case study business — a generic point ''could describe any business'' and earns zero application marks."}'::jsonb),
