('business:1-4-business-aims-objectives:match:e96b7b51', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Business Objectives”?", "options": ["The financial reward for taking risk in business, calculated as revenue minus total costs.", "The objective of simply keeping the business trading, especially important during early months or periods of difficulty.", "A business whose shares are traded on the stock exchange; shareholders expect profit and growth.", "The goals a business aims to achieve, such as profit, survival, growth, market share, or providing a service."]}'::jsonb, '{"answer": 3, "explain": "“Business Objectives” means: The goals a business aims to achieve, such as profit, survival, growth, market share, or providing a service."}'::jsonb),
('business:1-4-business-aims-objectives:match:10b9a22f', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit”?", "options": ["Making just enough profit to give the business owner a decent standard of living; common in small businesses.", "When a business becomes larger, for example by increasing sales, opening more outlets, or taking over a competitor.", "The financial reward for taking risk in business, calculated as revenue minus total costs.", "Prioritising customer satisfaction and meeting customer needs, even if it means making less profit."]}'::jsonb, '{"answer": 2, "explain": "“Profit” means: The financial reward for taking risk in business, calculated as revenue minus total costs."}'::jsonb),
('business:1-4-business-aims-objectives:match:e4c39173', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Satisficing”?", "options": ["A business''s sales expressed as a percentage of total sales in its market or industry.", "Prioritising customer satisfaction and meeting customer needs, even if it means making less profit.", "Making just enough profit to give the business owner a decent standard of living; common in small businesses.", "When a business becomes larger, for example by increasing sales, opening more outlets, or taking over a competitor."]}'::jsonb, '{"answer": 2, "explain": "“Satisficing” means: Making just enough profit to give the business owner a decent standard of living; common in small businesses."}'::jsonb),
