('business:1-4-business-aims-objectives:match:9205cf02', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Market Share”?", "options": ["A business''s sales expressed as a percentage of total sales in its market or industry.", "Prioritising customer satisfaction and meeting customer needs, even if it means making less profit.", "The objective of simply keeping the business trading, especially important during early months or periods of difficulty.", "The way a business develops and changes over time in terms of size, products, location, or methods."]}'::jsonb, '{"answer": 0, "explain": "“Market Share” means: A business''s sales expressed as a percentage of total sales in its market or industry."}'::jsonb),
('business:1-4-business-aims-objectives:match:9a1b6a7e', 'business', 'business:1-4-business-aims-objectives', '1.4 Aims and Objectives', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Survival”?", "options": ["The objective of simply keeping the business trading, especially important during early months or periods of difficulty.", "A business whose shares are traded on the stock exchange; shareholders expect profit and growth.", "Making just enough profit to give the business owner a decent standard of living; common in small businesses.", "Trying to make as much profit as possible — the opposite of satisficing."]}'::jsonb, '{"answer": 0, "explain": "“Survival” means: The objective of simply keeping the business trading, especially important during early months or periods of difficulty."}'::jsonb),
